export const TransactionIsolationLevelSchema = z.enum(['ReadUncommitted','ReadCommitted','RepeatableRead','Serializable']);

export const TagScalarFieldEnumSchema = z.enum(['id','slug','name','originalLocale','isUserCreated','isApproved','isHidden','isDeleted','createdBy','createdAt','updatedAt']);

export const TagTranslationScalarFieldEnumSchema = z.enum(['id','tagId','locale','name']);

export const ConnectionRequestScalarFieldEnumSchema = z.enum(['id','fromUserId','toUserId','scope','status','createdAt']);

export const UserScalarFieldEnumSchema = z.enum(['id','email','phonenumber','tokenVersion','loginToken','loginTokenExp','isActive','isBlocked','isRegistrationConfirmed','createdAt','updatedAt','lastLoginAt','language','originDomain','newsletterOptIn','emailNotificationsOptIn','roles','isPushNotificationEnabled']);

export const ProfileScalarFieldEnumSchema = z.enum(['id','publicName','country','cityName','isSocialActive','isDatingActive','isActive','isReported','isBlocked','isOnboarded','isCallable','hasFace','userId','work','languages','birthday','gender','pronouns','relationship','hasKids','prefAgeMin','prefAgeMax','prefGender','prefKids','lat','lon','createdAt','updatedAt']);

export const LocalizedProfileFieldScalarFieldEnumSchema = z.enum(['id','profileId','field','locale','value']);

export const ProfileImageScalarFieldEnumSchema = z.enum(['id','userId','profileId','position','altText','storagePath','url','width','height','mimeType','createdAt','updatedAt','contentHash','blurhash','isModerated','isFlagged','hasFace']);

export const ConversationScalarFieldEnumSchema = z.enum(['id','createdAt','updatedAt','profileAId','profileBId','status','initiatorProfileId','jitsiRoomId']);

export const ConversationParticipantScalarFieldEnumSchema = z.enum(['id','profileId','conversationId','lastReadAt','isMuted','isArchived','isCallable']);

export const LikedProfileScalarFieldEnumSchema = z.enum(['id','fromId','toId','createdAt','isNew','isAnonymous']);

export const HiddenProfileScalarFieldEnumSchema = z.enum(['id','fromId','toId','createdAt']);

export const MessageScalarFieldEnumSchema = z.enum(['id','conversationId','senderId','content','messageType','createdAt']);

export const MessageAttachmentScalarFieldEnumSchema = z.enum(['id','messageId','filePath','mimeType','fileSize','duration','createdAt']);

export const PushSubscriptionScalarFieldEnumSchema = z.enum(['id','userId','endpoint','p256dh','auth','createdAt','updatedAt','deviceInfo','lastSeen']);

export const UserContentScalarFieldEnumSchema = z.enum(['id','kind','postedById','content','isDeleted','isVisible','country','cityName','lat','lon','createdAt','updatedAt']);

export const PostContentScalarFieldEnumSchema = z.enum(['userContentId','type']);

export const EventContentScalarFieldEnumSchema = z.enum(['userContentId','startsAt']);

export const ProfileSessionLogScalarFieldEnumSchema = z.enum(['id','profileId','startedAt']);

export const ProfileActivitySummaryScalarFieldEnumSchema = z.enum(['profileId','firstSeenAt','lastSeenAt','activeDays28','sessions28','segment','demotionStreak','segmentUpdatedAt']);

export const ProfileTrustFlagScalarFieldEnumSchema = z.enum(['id','profileId','reason','flaggedAt','clearedAt','clearedBy','evidence','flaggedBy']);

export const MessageTemplateScalarFieldEnumSchema = z.enum(['id','type','locale','content','createdAt','updatedAt']);

export const SortOrderSchema = z.enum(['asc','desc']);

export const QueryModeSchema = z.enum(['default','insensitive']);

export const NullsOrderSchema = z.enum(['first','last']);

export const ConnectionTypeSchema = z.enum(['friend','dating']);

export type ConnectionTypeType = `${z.infer<typeof ConnectionTypeSchema>}`

export const ConnectionStatusSchema = z.enum(['pending','accepted','rejected','blocked']);

export type ConnectionStatusType = `${z.infer<typeof ConnectionStatusSchema>}`

export const GenderSchema = z.enum(['male','female','agender','androgynous','bigender','cis_man','cis_woman','genderfluid','genderqueer','gender_nonconforming','hijra','intersex','pangender','transfeminine','trans_man','transmasculine','transsexual','trans_woman','two_spirit','non_binary','other','unspecified']);

export type GenderType = `${z.infer<typeof GenderSchema>}`

export const PronounsSchema = z.enum(['he_him','she_her','they_them','unspecified']);

export type PronounsType = `${z.infer<typeof PronounsSchema>}`

export const HasKidsSchema = z.enum(['yes','no','unspecified']);

export type HasKidsType = `${z.infer<typeof HasKidsSchema>}`

export const RelationshipStatusSchema = z.enum(['single','in_relationship','married','divorced','widowed','other','unspecified']);

export type RelationshipStatusType = `${z.infer<typeof RelationshipStatusSchema>}`

export const UserRoleSchema = z.enum(['user','user_dating','admin','moderator']);

export type UserRoleType = `${z.infer<typeof UserRoleSchema>}`

export const PostTypeSchema = z.enum(['OFFER','REQUEST']);

export type PostTypeType = `${z.infer<typeof PostTypeSchema>}`

export const ContentKindSchema = z.enum(['post','event']);

export type ContentKindType = `${z.infer<typeof ContentKindSchema>}`

export const ActivitySegmentSchema = z.enum(['new','returning','frequent','dormant']);

export type ActivitySegmentType = `${z.infer<typeof ActivitySegmentSchema>}`

export const ConversationStatusSchema = z.enum(['INITIATED','ACCEPTED','BLOCKED','ARCHIVED','PENDING','DISCARDED']);

export type ConversationStatusType = `${z.infer<typeof ConversationStatusSchema>}`

export const TrustReasonSchema = z.enum(['PROFILE_UNVETTED','SPAM_BURST']);

export type TrustReasonType = `${z.infer<typeof TrustReasonSchema>}`

export const MessageTemplateTypeSchema = z.enum(['welcome']);

export type MessageTemplateTypeType = `${z.infer<typeof MessageTemplateTypeSchema>}`

